import models from '../modelData/models';

/**
 * fetchModel - Giả lập việc gọi API từ Web Server
 * Đáp ứng yêu cầu Problem 2: trả về Promise và JSON-encoded data
 */
function fetchModel(url) {
  return new Promise((resolve, reject) => {
    // Giả lập độ trễ mạng 200ms cho giống thật
    setTimeout(() => {
      let result = null;

      if (url === "/user/list") {
        result = models.userListModel();
      } else if (url.startsWith("/user/")) {
        const id = url.substring(6); // Lấy phần ID sau /user/
        result = models.userModel(id);
      } else if (url.startsWith("/photosOfUser/")) {
        const id = url.substring(14); // Lấy phần ID sau /photosOfUser/
        result = models.photoOfUserModel(id);
      } else if (url === "/test/info") {
        result = models.schemaInfo();
      }

      if (result) {
        // Trả về đúng cấu trúc { data: ... } mà các component đang đợi
        resolve({ data: result });
      } else {
        reject(new Error(`URL không hợp lệ hoặc không có dữ liệu: ${url}`));
      }
    }, 200);
  });
}

export default fetchModel;
